import{_ as e,o as i,c as s,ag as r}from"./chunks/framework.WmBmIPw-.js";const u=JSON.parse('{"title":"基础启发式（Simple Heuristics）","description":"","frontmatter":{},"headers":[],"relativePath":"or-opt/heuristics/simple/simple-heuristics.md","filePath":"or-opt/heuristics/simple/simple-heuristics.md","lastUpdated":1777190173000}'),a={name:"or-opt/heuristics/simple/simple-heuristics.md"};function l(o,t,h,m,p,c){return i(),s("div",null,[...t[0]||(t[0]=[r('<h1 id="基础启发式-simple-heuristics" tabindex="-1">基础启发式（Simple Heuristics） <a class="header-anchor" href="#基础启发式-simple-heuristics" aria-label="Permalink to &quot;基础启发式（Simple Heuristics）&quot;">​</a></h1><p>基础启发式指面向问题结构直接设计的规则、贪心、邻域上短链改进等，通常不依赖跨问题的通用元层迭代框架。文献中常再分为构造式与改进式（定义与 <a href="./../heuristic-algorithms.html">启发式算法总览</a> 中第一类下两子折叠一致）：</p><ul><li><strong>构造式</strong>（constructive）：从空或部分解逐步追加至完整可行解，或等价的逐步生成。本库已写：<a href="./greedy-algorithm.html">贪心</a>、<a href="./insertion-heuristics.html">插入启发式</a>、<a href="./clarke-wright-savings.html">Clarke–Wright 节约</a>。</li><li><strong>改进式</strong>（improvement）：从已有可行解出发，在邻域内作有限步改进或局部搜子过程。本库已写：<a href="./hill-climbing.html">爬山</a>、<a href="./k-opt.html">2-opt / 3-opt / k-opt</a>。</li></ul><p>二者常组合为「先构造、再改进」。与元启发式、精确法的配合见 <a href="./../heuristic-algorithms.html">启发式算法总览</a> 中「一、基础启发式」及下两项折叠；元启发式总览见 <a href="./../metaheuristics.html">元启发式</a>。</p><p><strong>注</strong>：表意与上界/热启动的用法、典型反例，可在各子页与 <a href="./../../exact/exact-algorithms.html">精确算法总览</a> 对照中逐步补全。</p>',5)])])}const _=e(a,[["render",l]]);export{u as __pageData,_ as default};
